-- Preguntas frecuentes de la clínica de gastroenterología

INSERT INTO preguntas_frecuentes (categoria, pregunta, respuesta) VALUES
('horarios', '¿Cuáles son los horarios de atención?', 'Atendemos de lunes a viernes de 8:00 a 18:00 hs y sábados de 8:00 a 13:00 hs. Para consultas de guardia, por favor comunicarse directamente al local.'),

('turnos', '¿Cómo saco un turno?', 'Podés sacar tu turno directamente por este chat. Solo necesitamos tu nombre completo, DNI y obra social. Te asignaremos el primer horario disponible y te enviaremos un código de turno para que puedas consultarlo o cancelarlo en cualquier momento.'),

('turnos', '¿Con cuánta anticipación puedo cancelar mi turno?', 'Para cancelar tu turno necesitás hacerlo con al menos 2 horas de anticipación y contar con tu código de turno. Si no tenés el código o necesitás cancelar con menos tiempo, comunicate directamente con nuestra secretaría.'),

('obras_sociales', '¿Qué obras sociales aceptan?', 'Trabajamos con la mayoría de las obras sociales y prepagas. Entre ellas: OSDE, Swiss Medical, Galeno, IOMA, PAMI, Medicus, Accord Salud, OSECAC, OSPRERA y muchas más. Para confirmar si tu cobertura está incluida, escribinos el nombre de tu obra social y te respondemos al instante.'),

('obras_sociales', '¿Necesito autorización previa de mi obra social?', 'Depende de tu cobertura. Algunas obras sociales requieren autorización previa para la consulta o para estudios. Te recomendamos consultar con tu obra social antes del turno. En caso de dudas, podés contactar a nuestra secretaría y te orientamos.'),

('documentacion', '¿Qué tengo que traer a la consulta?', 'Para la consulta debés traer: DNI, credencial de obra social o prepaga, orden médica si tu cobertura la requiere, y estudios previos relacionados con tu consulta (análisis, ecografías, tomografías, etc.) si los tenés.'),

('ubicacion', '¿Dónde están ubicados?', 'Nos encontramos en [DIRECCIÓN DE LA CLÍNICA]. Contamos con estacionamiento en la zona. Si necesitás indicaciones más precisas, podés contactar a nuestra secretaría.'),

('estudios', '¿Realizan colonoscopias y endoscopias?', 'Sí, realizamos estudios endoscópicos. Los turnos para colonoscopias y endoscopias son asignados por nuestra secretaría luego de la consulta médica. Si ya tenés indicación médica, comunicate con nosotros para coordinar el estudio.'),

('estudios', '¿Cómo me preparo para una colonoscopia?', 'La preparación para colonoscopia requiere dieta especial los días previos y un kit de preparación intestinal. Las instrucciones detalladas te las entregamos al momento de asignar el turno del estudio. Es muy importante seguirlas al pie de la letra para que el procedimiento pueda realizarse correctamente.'),

('estudios', '¿Necesito acompañante para los estudios?', 'Sí, para estudios con sedación (colonoscopia, endoscopia) es obligatorio contar con un acompañante que te retire de la clínica. No podrás conducir ni tomar transporte público solo luego del procedimiento.'),

('resultados', '¿Cuándo recibo los resultados de mis estudios?', 'Los resultados de los estudios endoscópicos están disponibles generalmente dentro de las 24 a 72 horas hábiles. Te avisamos por WhatsApp cuando estén listos. Las biopsias pueden demorar entre 7 y 10 días hábiles.'),

('pagos', '¿Atienden pacientes particulares?', 'Sí, atendemos pacientes particulares. Para conocer los aranceles vigentes, comunicate con nuestra secretaría. Los valores pueden variar según el tipo de consulta o estudio.');